solution_code:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char *my_strdup(const char *src) {
    size_t len = strlen(src);
    char *dst = malloc(len + 1);
    if (!dst) return NULL;
    strcpy(dst, src);
    return dst;
}

validation.test_code:
char *my_strdup(const char *src);

void test_strdup_basic(void) {
    char *s = my_strdup("hello");
    TEST_ASSERT_NOT_NULL(s);
    TEST_ASSERT_EQUAL_STRING("hello", s);
    free(s);
}

void test_strdup_independent(void) {
    char *s = my_strdup("test");
    TEST_ASSERT_NOT_NULL(s);
    s[0] = 'T';
    TEST_ASSERT_EQUAL_STRING("Test", s);
    free(s);
}

void test_strdup_empty(void) {
    char *s = my_strdup("");
    TEST_ASSERT_NOT_NULL(s);
    TEST_ASSERT_EQUAL_STRING("", s);
    free(s);
}

void test_strdup_long_string(void) {
    const char *original = "This is a longer string for testing";
    char *copy = my_strdup(original);
    TEST_ASSERT_NOT_NULL(copy);
    TEST_ASSERT_EQUAL_STRING(original, copy);
    free(copy);
}

int main(void) {
    RUN_TEST(test_strdup_basic);
    RUN_TEST(test_strdup_independent);
    RUN_TEST(test_strdup_empty);
    RUN_TEST(test_strdup_long_string);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

